using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>Comportamento de movimento "de fundo" do NPC, fora de ações de cutscene.</summary>
public enum NpcMovementMode
{
    Idle,
    FollowPlayer,
    FleePlayer,
    Patrol
}

/// <summary>Como a patrulha se comporta ao chegar a uma das pontas do percurso.</summary>
public enum PatrolLoopMode
{
    /// <summary>Ao chegar ao último ponto, salta directamente de volta para o primeiro.</summary>
    Loop,

    /// <summary>Ao chegar a uma ponta, inverte a direção (vai e volta).</summary>
    PingPong
}

/// <summary>
/// Controla o movimento básico do NPC (parado / seguir / fugir / patrulhar),
/// com detecção opcional de paredes e bordas de plataforma, viragem do sprite
/// (flipX) consoante a direção, e um parâmetro de Animator opcional para
/// animações de andar/parado.
///
/// Também expõe MoveDirectionForTime (Action_MoveNpc, Etapa 1) e
/// MoveToPosition (Action_MoveToTarget, Etapa 4) para movimento controlado
/// por cutscenes.
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
public class NpcMovement : MonoBehaviour
{
    [Header("Comportamento Base")]
    [SerializeField] private NpcMovementMode defaultMode = NpcMovementMode.Idle;
    [SerializeField] private float defaultSpeed = 2f;
    [SerializeField] private float stopDistance = 0.1f;
    [SerializeField] private float followRange = 5f;
    [SerializeField] private float fleeRange = 3f;

    [Header("Patrulha")]
    [Tooltip("Pontos de patrulha, como deslocamento (offset) relativo à posição inicial do NPC.")]
    [SerializeField] private List<Vector2> patrolPoints = new List<Vector2>();
    [SerializeField] private PatrolLoopMode patrolLoopMode = PatrolLoopMode.PingPong;
    [Tooltip("Tempo parado em cada ponto antes de seguir para o próximo.")]
    [SerializeField] private float patrolWaitTime = 1f;

    [Header("Detecção de Paredes/Bordas (opcional)")]
    [Tooltip("Camadas consideradas 'chão'/'parede'. Deixa em \"Nothing\" para desligar a detecção (recomendado: não incluir a layer do próprio NPC).")]
    [SerializeField] private LayerMask groundMask;
    [Tooltip("Se activo, o NPC não anda para fora de uma plataforma (Follow/Flee/Patrol).")]
    [SerializeField] private bool respectLedges = true;
    [SerializeField] private float wallCheckDistance = 0.3f;
    [SerializeField] private float groundCheckDistance = 0.6f;
    [Tooltip("Deslocamento vertical do ponto de onde parte o raio de detecção de chão (o X é espelhado consoante a direção do movimento).")]
    [SerializeField] private Vector2 groundCheckOffset = new Vector2(0.4f, 0f);

    [Header("Visual")]
    [Tooltip("Auto-detectado se vazio.")]
    [SerializeField] private SpriteRenderer spriteRenderer;
    [Tooltip("Se activo, o sprite vira (flipX) consoante a direção do movimento.")]
    [SerializeField] private bool faceMovementDirection = true;
    [Tooltip("Desliga se o sprite, com flipX = false, olha por defeito para a esquerda.")]
    [SerializeField] private bool spriteFacesRightByDefault = true;

    [Header("Animação (opcional)")]
    [Tooltip("Auto-detectado se vazio. Se atribuído, o parâmetro float abaixo recebe a velocidade horizontal (em unidades/seg).")]
    [SerializeField] private Animator animator;
    [SerializeField] private string animSpeedParam = "Speed";

    private Rigidbody2D _rb;
    private Transform _player;
    private int _animSpeedHash = -1;

    private Vector2 _startPosition;
    private int _patrolIndex;
    private int _patrolDir = 1;
    private float _patrolWaitTimer;

    /// <summary>Enquanto true, o comportamento base (idle/follow/flee/patrol) fica suspenso porque uma ação de cutscene está a controlar o movimento.</summary>
    private bool _actionOverride;

    /// <summary>Enquanto true, o comportamento base está suspenso por Pause() (Etapa 8 — ver Action_PauseNearbyNpcs).</summary>
    private bool _movementPaused;
    private NpcMovementMode _modeBeforePause;

    public NpcMovementMode DefaultMode { get => defaultMode; set => defaultMode = value; }
    public float DefaultSpeed { get => defaultSpeed; set => defaultSpeed = value; }
    public bool IsMovementPaused => _movementPaused;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();

        if (spriteRenderer == null)
            spriteRenderer = GetComponent<SpriteRenderer>();

        if (animator == null)
            animator = GetComponent<Animator>();

        if (animator != null && !string.IsNullOrEmpty(animSpeedParam))
            _animSpeedHash = Animator.StringToHash(animSpeedParam);
    }

    private void Start()
    {
        _startPosition = transform.position;

        var npc = GetComponent<NpcController>();
        _player = npc != null ? npc.Player : null;

        if (_player == null)
            _player = PlayerLocator.Find();
    }

    private void FixedUpdate()
    {
        if (!_actionOverride)
        {
            switch (defaultMode)
            {
                case NpcMovementMode.Idle:
                    break;

                case NpcMovementMode.FollowPlayer:
                    ApplyFollow();
                    break;

                case NpcMovementMode.FleePlayer:
                    ApplyFlee();
                    break;

                case NpcMovementMode.Patrol:
                    ApplyPatrol();
                    break;
            }
        }

        UpdateAnimator();
    }

    private void ApplyFollow()
    {
        if (_player == null) return;

        float dist = Vector2.Distance(_player.position, transform.position);
        if (dist <= stopDistance || dist > followRange)
        {
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        float dir = Mathf.Sign(_player.position.x - transform.position.x);

        if (!CanMove(dir))
        {
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        _rb.linearVelocity = new Vector2(dir * defaultSpeed, _rb.linearVelocity.y);
        FaceDirection(dir);
    }

    private void ApplyFlee()
    {
        if (_player == null) return;

        float dist = Vector2.Distance(_player.position, transform.position);
        if (dist > fleeRange)
        {
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        float dir = Mathf.Sign(transform.position.x - _player.position.x);

        if (!CanMove(dir))
        {
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        _rb.linearVelocity = new Vector2(dir * defaultSpeed, _rb.linearVelocity.y);
        FaceDirection(dir);
    }

    private void ApplyPatrol()
    {
        if (patrolPoints == null || patrolPoints.Count == 0) return;

        if (_patrolWaitTimer > 0f)
        {
            _patrolWaitTimer -= Time.fixedDeltaTime;
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        Vector2 target = _startPosition + patrolPoints[_patrolIndex];
        float dx = target.x - transform.position.x;

        if (Mathf.Abs(dx) <= stopDistance)
        {
            _patrolWaitTimer = patrolWaitTime;
            AdvancePatrolIndex();
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        float dir = Mathf.Sign(dx);

        if (!CanMove(dir))
        {
            // Obstáculo ou borda à frente: espera e avança o índice (tenta o próximo ponto).
            _patrolWaitTimer = patrolWaitTime;
            AdvancePatrolIndex();
            _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            return;
        }

        _rb.linearVelocity = new Vector2(dir * defaultSpeed, _rb.linearVelocity.y);
        FaceDirection(dir);
    }

    private void AdvancePatrolIndex()
    {
        if (patrolPoints.Count <= 1) return;

        if (patrolLoopMode == PatrolLoopMode.Loop)
        {
            _patrolIndex = (_patrolIndex + 1) % patrolPoints.Count;
            return;
        }

        // PingPong
        if (_patrolIndex + _patrolDir < 0 || _patrolIndex + _patrolDir >= patrolPoints.Count)
            _patrolDir = -_patrolDir;

        _patrolIndex += _patrolDir;
    }

    /// <summary>Verifica se o NPC pode avançar na direção "dir" (±1) sem bater numa parede ou cair de uma borda.</summary>
    private bool CanMove(float dir)
    {
        if (groundMask.value == 0) return true;

        if (wallCheckDistance > 0f)
        {
            var wallHit = Physics2D.Raycast(transform.position, new Vector2(dir, 0f), wallCheckDistance, groundMask);
            if (wallHit.collider != null) return false;
        }

        if (respectLedges && groundCheckDistance > 0f)
        {
            Vector2 origin = (Vector2)transform.position + new Vector2(groundCheckOffset.x * Mathf.Sign(dir), groundCheckOffset.y);
            var groundHit = Physics2D.Raycast(origin, Vector2.down, groundCheckDistance, groundMask);
            if (groundHit.collider == null) return false;
        }

        return true;
    }

    /// <summary>Vira o sprite (flipX) para olhar na direção "dirX" (positivo = direita, negativo = esquerda). Não faz nada se dirX for ~0.</summary>
    public void FaceDirection(float dirX)
    {
        if (!faceMovementDirection || spriteRenderer == null || Mathf.Approximately(dirX, 0f)) return;

        bool facingRight = dirX > 0f;
        spriteRenderer.flipX = spriteFacesRightByDefault ? !facingRight : facingRight;
    }

    /// <summary>Vira o sprite para olhar para uma posição do mundo (ex: o player), com base na diferença no eixo X.</summary>
    public void FaceTowards(Vector2 worldPosition)
    {
        FaceDirection(worldPosition.x - transform.position.x);
    }

    private void UpdateAnimator()
    {
        if (animator == null || _animSpeedHash == -1) return;
        animator.SetFloat(_animSpeedHash, Mathf.Abs(_rb.linearVelocity.x));
    }

    /// <summary>
    /// Move o NPC numa direção fixa, a uma velocidade, durante "duration" segundos.
    /// Usado por Action_MoveNpc. Suspende o comportamento base (idle/follow/flee/patrol)
    /// enquanto corre e restaura-o no fim.
    /// </summary>
    public IEnumerator MoveDirectionForTime(Vector2 direction, float speed, float duration)
    {
        _actionOverride = true;

        direction = direction.normalized;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            float vy = direction.y == 0f ? _rb.linearVelocity.y : direction.y * speed;
            _rb.linearVelocity = new Vector2(direction.x * speed, vy);
            FaceDirection(direction.x);

            elapsed += Time.deltaTime;
            yield return null;
        }

        _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
        _actionOverride = false;
    }

    /// <summary>
    /// Move o NPC horizontalmente até ficar a "arriveDistance" de "target" (eixo X).
    /// Usado por Action_MoveToTarget. Suspende o comportamento base enquanto corre.
    /// "timeout" em segundos evita ficar preso para sempre se o alvo for
    /// inalcançável (0 = sem limite).
    /// </summary>
    public IEnumerator MoveToPosition(Transform target, float speed, float arriveDistance, float timeout)
    {
        _actionOverride = true;
        float elapsed = 0f;

        while (target != null)
        {
            float dx = target.position.x - transform.position.x;
            if (Mathf.Abs(dx) <= arriveDistance) break;

            float dir = Mathf.Sign(dx);
            _rb.linearVelocity = new Vector2(dir * speed, _rb.linearVelocity.y);
            FaceDirection(dir);

            elapsed += Time.fixedDeltaTime;
            if (timeout > 0f && elapsed >= timeout) break;

            yield return new WaitForFixedUpdate();
        }

        _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
        _actionOverride = false;
    }

    /// <summary>Liberta um override de movimento (segurança, caso uma ação seja interrompida a meio).</summary>
    public void ReleaseOverride()
    {
        _actionOverride = false;
    }

    /// <summary>
    /// Suspende o comportamento base (Follow/Flee/Patrol), guardando o
    /// "DefaultMode" actual para Resume() restaurar, e pára o movimento
    /// horizontal. Não faz nada se já estiver pausado. Usado por
    /// Action_PauseNearbyNpcs (Etapa 8). Devolve true se este NPC passou a
    /// estar pausado agora (false se já estava).
    /// </summary>
    public bool Pause()
    {
        if (_movementPaused) return false;

        _movementPaused = true;
        _modeBeforePause = defaultMode;
        defaultMode = NpcMovementMode.Idle;

        if (_rb != null) _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);

        return true;
    }

    /// <summary>Restaura o "DefaultMode" guardado por Pause(). Não faz nada se não estiver pausado.</summary>
    public void Resume()
    {
        if (!_movementPaused) return;

        _movementPaused = false;
        defaultMode = _modeBeforePause;
    }

    /// <summary>
    /// Foge horizontalmente de "from" (ex: o player) durante "duration" segundos,
    /// recalculando a direção a cada passo de física — funciona mesmo que "from"
    /// se mova durante a fuga. Usado por Action_FleeFromPlayer. Suspende o
    /// comportamento base enquanto corre.
    /// </summary>
    public IEnumerator FleeFromTransform(Transform from, float speed, float duration)
    {
        if (from == null) yield break;

        _actionOverride = true;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            float dir = Mathf.Sign(transform.position.x - from.position.x);
            if (dir == 0f) dir = 1f;

            if (CanMove(dir))
            {
                _rb.linearVelocity = new Vector2(dir * speed, _rb.linearVelocity.y);
                FaceDirection(dir);
            }
            else
            {
                _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
            }

            elapsed += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
        _actionOverride = false;
    }

    /// <summary>
    /// Aplica um impulso vertical (salto). Se "groundMask" estiver configurado e
    /// o NPC não estiver no chão, não faz nada e devolve false. Usado por Action_Jump.
    /// </summary>
    public bool Jump(float force)
    {
        if (!IsGrounded()) return false;

        _rb.linearVelocity = new Vector2(_rb.linearVelocity.x, force);
        return true;
    }

    /// <summary>Verifica se o NPC está actualmente apoiado em "groundMask" (true sempre que "groundMask" não estiver configurado).</summary>
    private bool IsGrounded()
    {
        if (groundMask.value == 0) return true;

        var hit = Physics2D.Raycast(transform.position, Vector2.down, groundCheckDistance, groundMask);
        return hit.collider != null;
    }

    /// <summary>
    /// Espera até o NPC voltar a tocar em "groundMask" (ex: depois de Jump),
    /// até "timeout" segundos (0 = sem limite). Usado por Action_Jump.
    /// </summary>
    public IEnumerator WaitUntilGrounded(float timeout)
    {
        float elapsed = 0f;

        // Espera primeiro deixar o chão, para não detectar "aterrou" no mesmo frame do salto.
        yield return new WaitForFixedUpdate();

        while (!IsGrounded())
        {
            elapsed += Time.fixedDeltaTime;
            if (timeout > 0f && elapsed >= timeout) yield break;
            yield return new WaitForFixedUpdate();
        }
    }

    private void OnDrawGizmosSelected()
    {
        if (patrolPoints == null || patrolPoints.Count == 0) return;

        Vector2 basePos = Application.isPlaying ? _startPosition : (Vector2)transform.position;

        Gizmos.color = Color.yellow;
        Vector2 prev = basePos;

        foreach (var offset in patrolPoints)
        {
            Vector2 point = basePos + offset;
            Gizmos.DrawWireSphere(point, 0.15f);
            Gizmos.DrawLine(prev, point);
            prev = point;
        }

        if (patrolLoopMode == PatrolLoopMode.Loop && patrolPoints.Count > 1)
            Gizmos.DrawLine(prev, basePos + patrolPoints[0]);
    }
}
